const o=new IntersectionObserver(e=>{e.forEach(n=>{n.isIntersecting&&n.target.classList.add("visible")})},{threshold:.1});document.querySelectorAll(".animate-on-scroll").forEach(e=>{o.observe(e)});const c=document.getElementById("hamburger"),t=document.getElementById("mobile-nav"),l=document.getElementById("mobile-close"),i=document.querySelectorAll(".mobile-nav-link");function d(){t?.classList.remove("hidden"),t?.classList.add("flex")}function s(){t?.classList.add("hidden"),t?.classList.remove("flex")}c?.addEventListener("click",d);l?.addEventListener("click",s);i.forEach(e=>e.addEventListener("click",s));
